/// Get MCMC samples slice for a given model
pub fn mcmc_samples(model: Model) -> &'static [[f64; 4]] {
    match model {
        Model::EvIm => MCMC_EVIM,
        Model::EcIm => MCMC_ECIM,
        Model::EEnIm => MCMC_EENIM,
        Model::EbIm => MCMC_EBIM,
        Model::EUnIm => MCMC_EUNIM,
        Model::EUnCasubq => MCMC_EUNCASUBQ,
        Model::PatchTw => MCMC_PATCHTW,
        Model::PatchOw => MCMC_PATCHOW,
    }
}
